import{_ as t,a,b as n,c as r,d as o,e as d,f as i}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as l,o as s,c as h,a2 as c}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Add a Discord Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/discord.md","filePath":"en/upload/discord.md","lastUpdated":1781962217000}'),p={name:"en/upload/discord.md"};function u(b,e,m,g,f,v){return s(),h("div",null,[...e[0]||(e[0]=[c('<h1 id="add-a-discord-channel" tabindex="-1">Add a Discord Channel <a class="header-anchor" href="#add-a-discord-channel" aria-label="Permalink to &quot;Add a Discord Channel&quot;">​</a></h1><h2 id="what-you-need-before-you-start" tabindex="-1">What You Need Before You Start <a class="header-anchor" href="#what-you-need-before-you-start" aria-label="Permalink to &quot;What You Need Before You Start&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>Discord account</td><td>Used to create a server, channel, and developer application.</td></tr><tr><td>A Discord server</td><td>The bot must join a server before it can access a channel.</td></tr><tr><td>A text channel</td><td>Images and files will be sent to this channel.</td></tr><tr><td>Discord Developer Portal</td><td>Used to create an application, create a bot, and get the <code>Bot Token</code>.</td></tr></tbody></table><h2 id="where-to-add-it" tabindex="-1">Where to Add It <a class="header-anchor" href="#where-to-add-it" aria-label="Permalink to &quot;Where to Add It&quot;">​</a></h2><ol><li>Open System Settings.</li><li>Go to Upload Settings.</li><li>Click Add Channel in the upper-right corner.</li><li>Select <code>Discord</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>What It Does</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>A friendly name for this channel, such as &quot;Discord Primary&quot;.</td><td>Required</td></tr><tr><td>Bot Token</td><td>The Discord bot token.</td><td>Required</td></tr><tr><td>Channel ID</td><td>The ID of the target text channel.</td><td>Required</td></tr><tr><td>Proxy URL (optional)</td><td>Use this only if Discord CDN access is unstable. Enter the full URL, including <code>https://</code>.</td><td>Optional</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="_1-create-a-discord-server-and-text-channel" tabindex="-1">1. Create a Discord Server and Text Channel <a class="header-anchor" href="#_1-create-a-discord-server-and-text-channel" aria-label="Permalink to &quot;1. Create a Discord Server and Text Channel&quot;">​</a></h3><ol><li>Open Discord.</li><li>Create a new server, or use an existing server you own.</li><li>Create a text channel in that server.</li></ol><p><img src="'+t+'" alt="Create a server" loading="lazy"></p><h3 id="_2-create-a-bot-in-the-discord-developer-portal" tabindex="-1">2. Create a Bot in the Discord Developer Portal <a class="header-anchor" href="#_2-create-a-bot-in-the-discord-developer-portal" aria-label="Permalink to &quot;2. Create a Bot in the Discord Developer Portal&quot;">​</a></h3><ol><li>Open the Discord Developer Portal: <code>https://discord.com/developers/applications</code></li><li>Click <code>New Application</code>.</li><li>Enter an application name and create it.</li><li>Open the <code>Bot</code> page from the left sidebar.</li><li>Generate or reset the token on the <code>Bot</code> page.</li><li>Save the token.</li></ol><p>This token is the <code>Bot Token</code> you need to enter in ImgBed.</p><p><img src="'+a+'" alt="View the bot token" loading="lazy"></p><h3 id="_3-generate-an-oauth2-invite-link-and-install-the-bot" tabindex="-1">3. Generate an OAuth2 Invite Link and Install the Bot <a class="header-anchor" href="#_3-generate-an-oauth2-invite-link-and-install-the-bot" aria-label="Permalink to &quot;3. Generate an OAuth2 Invite Link and Install the Bot&quot;">​</a></h3><ol><li>Open the <code>OAuth2</code> page from the left sidebar.</li><li>Under scopes, select <code>bot</code>.</li><li>In the permission area, enable these permissions:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Required</th></tr></thead><tbody><tr><td>View Channels</td><td>Yes</td></tr><tr><td>Send Messages</td><td>Yes</td></tr><tr><td>Attach Files</td><td>Yes</td></tr><tr><td>Read Message History</td><td>Yes</td></tr></tbody></table><ol start="4"><li>At the bottom of the page, confirm that the integration type is <code>Guild Install</code>.</li><li>Copy the generated URL.</li><li>Open that URL in your browser.</li><li>Select the target server.</li><li>Complete the authorization flow.</li></ol><p><img src="'+n+'" alt="Select bot permissions in OAuth2" loading="lazy"></p><p><img src="'+r+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-enable-developer-mode-and-copy-the-channel-id" tabindex="-1">4. Enable Developer Mode and Copy the Channel ID <a class="header-anchor" href="#_4-enable-developer-mode-and-copy-the-channel-id" aria-label="Permalink to &quot;4. Enable Developer Mode and Copy the Channel ID&quot;">​</a></h3><ol><li>Click the gear icon next to your avatar in the lower-left corner of Discord.</li><li>Open Advanced from the left sidebar.</li><li>Enable Developer Mode.</li><li>Return to the target text channel.</li><li>Right-click the channel name.</li><li>Click Copy Channel ID.</li></ol><p>The copied number is the <code>Channel ID</code> required by ImgBed.</p><p><img src="'+o+'" alt="Enable developer mode" loading="lazy"></p><p><img src="'+d+'" alt="Copy the channel ID" loading="lazy"></p><h3 id="_5-fill-in-the-discord-channel-in-imgbed" tabindex="-1">5. Fill in the Discord Channel in ImgBed <a class="header-anchor" href="#_5-fill-in-the-discord-channel-in-imgbed" aria-label="Permalink to &quot;5. Fill in the Discord Channel in ImgBed&quot;">​</a></h3><p>Return to the channel configuration dialog and fill in the fields as follows:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel name</td><td>A custom channel name, for example <code>DiscordPrimary</code>.</td></tr><tr><td>Bot Token</td><td>The token saved from the <code>Bot</code> page in the Discord Developer Portal.</td></tr><tr><td>Channel ID</td><td>The channel ID you copied from Discord.</td></tr><tr><td>Proxy URL (optional)</td><td>Only if needed, for example <code>https://your-proxy.example.com</code>.</td></tr></tbody></table><p>Click Save when you are done.</p><p><img src="'+i+`" alt="Add the Discord channel configuration" loading="lazy"></p><h2 id="how-to-verify-it" tabindex="-1">How to Verify It <a class="header-anchor" href="#how-to-verify-it" aria-label="Permalink to &quot;How to Verify It&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>How to Verify</th></tr></thead><tbody><tr><td>Channel card appears</td><td>After saving, the Upload Settings page should show a Discord channel card.</td></tr><tr><td>Channel can be enabled</td><td>The Active switch should stay on.</td></tr><tr><td>Configuration is saved</td><td>The detail view should show that the Bot Token and Channel ID were saved.</td></tr><tr><td>Upload works</td><td>Upload a test image and confirm that it appears in the target Discord text channel.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Create a Discord server</span></span>
<span class="line"><span>-&gt; Create a text channel</span></span>
<span class="line"><span>-&gt; Create a bot in the Discord Developer Portal</span></span>
<span class="line"><span>-&gt; Save the Bot Token from the Bot page</span></span>
<span class="line"><span>-&gt; In OAuth2, select bot, View Channels, Send Messages, Attach Files, and Read Message History</span></span>
<span class="line"><span>-&gt; Copy the generated URL and authorize the bot for the target server</span></span>
<span class="line"><span>-&gt; Make sure the target text channel grants the same permissions</span></span>
<span class="line"><span>-&gt; Enable Developer Mode</span></span>
<span class="line"><span>-&gt; Right-click the target text channel and copy the Channel ID</span></span>
<span class="line"><span>-&gt; Enter the Bot Token and Channel ID in ImgBed</span></span>
<span class="line"><span>-&gt; Save and upload a test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const C=l(p,[["render",u]]);export{k as __pageData,C as default};
